mapper.select:
SELECT id, user_id, name, description, article_count, sort_order, default_folder, create_time, update_time
FROM collection_folder
WHERE id = #{id}

SELECT id, user_id, name, description, article_count, sort_order, default_folder, create_time, update_time
FROM collection_folder
WHERE user_id = #{userId} AND name = #{name}

mapper.update:
UPDATE collection_folder
name = #{name}, description = #{description}, article_count = #{articleCount}, sort_order = #{sortOrder}, default_folder = #{defaultFolder}, update_time = #{updateTime}
WHERE id = #{id}

UPDATE collection_folder
SET article_count = article_count + #{count}, update_time = NOW()
WHERE id = #{folderId}
